                if key == 'combined_score':
                    score = data[key]
                elif isinstance(data[key], dict):
                    score = data[key].get('combined_score')
        # Try nested
        if score is None and 'result' in data:
            score = data['result'].get('combined_score') if isinstance(data['result'], dict) else None
        print(f'{t}: score={score}')
